UPDATE luv_chassis_modules SET parameter_schema = '[{"key": "height", "label": "Height", "type": "measurement", "tier": "basic", "description": "Standing height", "units": ["cm", "in"], "defaultUnit": "cm", "min": 140, "max": 200, "step": 1, "default": {"value": 170, "unit": "cm"}}, {"key": "build", "label": "Build", "type": "enum", "tier": "basic", "options": ["petite", "slim", "athletic", "average", "curvy", "muscular", "plus"], "default": "athletic"}, {"key": "age_appearance", "label": "Apparent Age", "type": "text", "tier": "basic", "description": "Age range the character appears to be"}, {"key": "bust", "label": "Bust Circumference", "type": "measurement", "tier": "basic", "description": "Fullest point around chest", "units": ["cm", "in"], "defaultUnit": "cm", "min": 70, "max": 130, "step": 0.5, "default": {"value": 88, "unit": "cm"}}, {"key": "waist", "label": "Waist Circumference", "type": "measurement", "tier": "basic", "description": "Natural waist, narrowest point of torso", "units": ["cm", "in"], "defaultUnit": "cm", "min": 50, "max": 110, "step": 0.5, "default": {"value": 66, "unit": "cm"}}, {"key": "hip", "label": "Hip Circumference", "type": "measurement", "tier": "basic", "description": "Fullest point around hips and posterior", "units": ["cm", "in"], "defaultUnit": "cm", "min": 70, "max": 140, "step": 0.5, "default": {"value": 94, "unit": "cm"}}, {"key": "shoulder_width", "label": "Shoulder Width", "type": "measurement", "tier": "intermediate", "description": "Biacromial breadth, point to point", "units": ["cm", "in"], "defaultUnit": "cm", "min": 30, "max": 50, "step": 0.5, "default": {"value": 38, "unit": "cm"}}, {"key": "underbust", "label": "Underbust", "type": "measurement", "tier": "intermediate", "description": "Band measurement directly below bust", "units": ["cm", "in"], "defaultUnit": "cm", "min": 60, "max": 110, "step": 0.5, "default": {"value": 74, "unit": "cm"}}, {"key": "inseam", "label": "Inseam", "type": "measurement", "tier": "intermediate", "description": "Crotch to ankle", "units": ["cm", "in"], "defaultUnit": "cm", "min": 60, "max": 95, "step": 0.5, "default": {"value": 78, "unit": "cm"}}, {"key": "torso_length", "label": "Torso Length", "type": "measurement", "tier": "intermediate", "description": "Shoulder to natural waist", "units": ["cm", "in"], "defaultUnit": "cm", "min": 35, "max": 55, "step": 0.5, "default": {"value": 43, "unit": "cm"}}, {"key": "bust_shape", "label": "Bust Shape", "type": "enum", "tier": "intermediate", "options": ["athletic", "natural-round", "teardrop", "full-round", "bell", "east-west", "side-set"], "default": "natural-round", "description": "Breast shape classification"}, {"key": "posterior_shape", "label": "Posterior Shape", "type": "enum", "tier": "intermediate", "options": ["flat", "V-shape", "square", "round", "heart", "A-shape", "bubble"], "default": "round", "description": "Gluteal contour viewed from behind"}, {"key": "waist_definition", "label": "Waist Definition", "type": "enum", "tier": "intermediate", "options": ["straight", "subtle", "defined", "hourglass", "extreme-hourglass"], "default": "defined", "description": "How sharply the waist narrows between ribcage and hips"}, {"key": "thigh_shape", "label": "Thigh Shape", "type": "enum", "tier": "intermediate", "options": ["slim", "toned", "athletic", "full", "thick"], "default": "toned"}, {"key": "arm_length", "label": "Arm Length", "type": "measurement", "tier": "advanced", "description": "Shoulder point to wrist crease", "units": ["cm", "in"], "defaultUnit": "cm", "min": 50, "max": 75, "step": 0.5, "default": {"value": 56, "unit": "cm"}}, {"key": "neck", "label": "Neck Circumference", "type": "measurement", "tier": "advanced", "description": "Base of neck circumference", "units": ["cm", "in"], "defaultUnit": "cm", "min": 28, "max": 45, "step": 0.5, "default": {"value": 33, "unit": "cm"}}, {"key": "bust_projection", "label": "Bust Projection", "type": "enum", "tier": "advanced", "options": ["flat", "subtle", "moderate", "prominent", "very-prominent"], "default": "moderate", "description": "How far the bust projects from the chest wall"}, {"key": "bust_position", "label": "Bust Position", "type": "enum", "tier": "advanced", "options": ["high", "medium-high", "medium", "medium-low", "low"], "default": "medium-high", "description": "Vertical position of bust apex relative to torso"}, {"key": "posterior_projection", "label": "Posterior Projection", "type": "enum", "tier": "advanced", "options": ["flat", "subtle", "moderate", "prominent", "very-prominent"], "default": "moderate", "description": "How far the posterior projects in profile"}, {"key": "tummy", "label": "Abdominal Contour", "type": "enum", "tier": "advanced", "options": ["flat", "toned", "defined-abs", "soft", "rounded"], "default": "toned", "description": "Shape and tone of the midsection"}, {"key": "navel_position", "label": "Navel Position", "type": "enum", "tier": "advanced", "options": ["high", "centered", "low"], "default": "centered", "description": "Vertical navel placement on torso"}, {"key": "hip_bones", "label": "Hip Bone Visibility", "type": "enum", "tier": "advanced", "options": ["hidden", "subtle", "visible", "prominent"], "default": "subtle", "description": "Iliac crest visibility"}, {"key": "groin_crease", "label": "Groin Crease Definition", "type": "enum", "tier": "advanced", "options": ["hidden", "subtle", "defined", "sharp"], "default": "subtle", "description": "V-line / inguinal crease definition"}, {"key": "calf_shape", "label": "Calf Shape", "type": "enum", "tier": "advanced", "options": ["slim", "defined", "athletic", "muscular", "full"], "default": "defined"}, {"key": "shoulder_to_hip", "label": "Shoulder-to-Hip", "type": "ratio", "tier": "clinical", "ratioLabels": ["Shoulder", "Hip"], "min": 0, "max": 1, "step": 0.05, "default": {"a": 0.45, "b": 0.55}}, {"key": "torso_to_leg", "label": "Torso-to-Leg", "type": "ratio", "tier": "clinical", "ratioLabels": ["Torso", "Legs"], "min": 0, "max": 1, "step": 0.05, "default": {"a": 0.45, "b": 0.55}}, {"key": "waist_to_hip_ratio", "label": "Waist-to-Hip Ratio", "type": "range", "tier": "clinical", "description": "WHR \u2014 waist divided by hip circumference (0.60\u20130.95 typical female range)", "min": 0.55, "max": 1.0, "step": 0.01, "default": 0.7}, {"key": "bust_to_underbust_diff", "label": "Bust-Underbust Difference", "type": "measurement", "tier": "clinical", "description": "Bust minus underbust \u2014 determines effective cup size (e.g. 14cm \u2248 D)", "units": ["cm", "in"], "defaultUnit": "cm", "min": 0, "max": 30, "step": 0.5, "default": {"value": 14, "unit": "cm"}}]'::jsonb WHERE slug = 'body-proportions';
